#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007
#define MAXN 55
long long fact[MAXN], invfact[MAXN];
long long powmod(long long a, long long b) {
    long long res = 1;
    while (b) {
        if (b & 1) res = (res * a) % MOD;
        a = (a * a) % MOD;
        b >>= 1;
    }
    return res;
}
long long comb(int n, int k) {
    return (fact[n] * invfact[k] % MOD * invfact[n - k]) % MOD;
}
int main() {
    int N, M, K;
    scanf("%d %d %d", &N, &M, &K);
    long long A[N][M];
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < M; j++) {
            scanf("%lld", &A[i][j]);
        }
    }
    fact[0] = 1;
    for (int i = 1; i <= N + M; i++) {
        fact[i] = (fact[i - 1] * i) % MOD;
    }
    invfact[N + M] = powmod(fact[N + M], MOD - 2);
    for (int i = N + M - 1; i >= 0; i--) {
        invfact[i] = (invfact[i + 1] * (i + 1)) % MOD;
    }
    long long ans = 0;
    for (int i = 0; i < N; i++) {
        long long sum = 0;
        for (int j = 0; j < M; j++) {
            sum = (sum + A[i][j]) % MOD;
        }
        ans = (ans + sum * powmod(sum, K - 1) % MOD * comb(N + M - 1, N - 1)) % MOD;
    }
    for (int j = 0; j < M; j++) {
        long long sum = 0;
        for (int i = 0; i < N; i++) {
            sum = (sum + A[i][j]) % MOD;
        }
        ans = (ans + sum * powmod(sum, K - 1) % MOD * comb(N + M - 1, M - 1)) % MOD;
    }
    printf("%lld\n", ans);
    return 0;
}

