// COMPLETE, COMPILABLE Java code
import java.util.Scanner;
public class Main {
    static final long MOD = 1000000007;
    static final int MAXN = 55;
    public static long powmod(long a, long b) {
        long res = 1;
        while (b > 0) {
            if ((b & 1) == 1) res = (res * a) % MOD;
            a = (a * a) % MOD;
            b >>= 1;
        }
        return res;
    }
    public static long comb(int n, int k) {
        long[] fact = new long[n + 1];
        fact[0] = 1;
        for (int i = 1; i <= n; i++) {
            fact[i] = (fact[i - 1] * i) % MOD;
        }
        long[] invfact = new long[n + 1];
        invfact[n] = powmod(fact[n], MOD - 2);
        for (int i = n - 1; i >= 0; i--) {
            invfact[i] = (invfact[i + 1] * (i + 1)) % MOD;
        }
        return (fact[n] * invfact[k] % MOD * invfact[n - k]) % MOD;
    }
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        int M = sc.nextInt();
        int K = sc.nextInt();
        long[][] A = new long[N][M];
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < M; j++) {
                A[i][j] = sc.nextLong();
            }
        }
        long ans = 0;
        for (int i = 0; i < N; i++) {
            long sum = 0;
            for (int j = 0; j < M; j++) {
                sum = (sum + A[i][j]) % MOD;
            }
            ans = (ans + sum * powmod(sum, K - 1) % MOD * comb(N + M - 1, N - 1)) % MOD;
        }
        for (int j = 0; j < M; j++) {
            long sum = 0;
            for (int i = 0; i < N; i++) {
                sum = (sum + A[i][j]) % MOD;
            }
            ans = (ans + sum * powmod(sum, K - 1) % MOD * comb(N + M - 1, M - 1)) % MOD;
        }
        System.out.println(ans);
    }
}

